import * as React from "react"
import { cn } from "@/lib/utils"
import { Vector as VectorLayer } from 'ol/layer'
import { Vector as VectorSource } from 'ol/source'
import Feature from 'ol/Feature'
import * as geom from 'ol/geom'
import * as style from 'ol/style'
import { fromLonLat } from 'ol/proj'
import type Map from 'ol/Map'
import { useMap } from '../gis-map-core/gis-map-core'

export type DrawType = 'Point' | 'LineString' | 'Polygon' | 'Circle' | 'Semicircle' | null

export interface PolygonStyle {
  icon?: {
    src?: string
    scale?: number
    displacementX?: number
    displacementY?: number
  }
  line?: {
    color?: string
    width?: number
    snumber?: boolean
  }
  polygon?: {
    color?: string
    width?: number
    fillColor?: string
    snumber?: boolean
  }
  circle?: {
    color?: string
    width?: number
    fillColor?: string
  }
  semicircle?: {
    color?: string
    width?: number
    fillColor?: string
  }
}

export interface PolygonData {
  id: string
  type: DrawType
  coordinates: number[] | number[][] | number[][][] | { center: number[]; radius: number }
  style?: PolygonStyle
}

export interface PolygonViewsProps {
  /**
   * 区域数据列表
   */
  data?: PolygonData[]
  /**
   * 默认样式配置
   */
  defaultStyle?: PolygonStyle
  /**
   * 当前绘制类型
   */
  drawType?: DrawType
  /**
   * 绘制类型变化回调
   */
  onDrawTypeChange?: (type: DrawType) => void
  /**
   * 数据变化回调
   */
  onDataChange?: (data: PolygonData[]) => void
  /**
   * 是否显示绘制工具栏
   */
  showToolbar?: boolean
  /**
   * 是否只读
   */
  readonly?: boolean
  /**
   * 是否显示
   */
  display?: boolean
  /**
   * CSS 类名
   */
  className?: string
  /**
   * 单元格唯一标识
   */
  cellKey?: string
  /**
   * 地图实例（由父组件传入）
   */
  map?: Map | null
}

// 默认点图标
const DEFAULT_POINT_ICON = 'data:image/svg+xml;base64,'

const PolygonViews = React.forwardRef<HTMLDivElement, PolygonViewsProps>(
  (
    {
      className,
      data = [],
      defaultStyle = {},
      drawType,
      onDrawTypeChange,
      onDataChange,
      showToolbar = false,
      readonly = false,
      display = true,
      cellKey,
      map: mapProp,
      ...props
    },
    ref
  ) => {
    const contextMap = useMap()
    const map = mapProp || contextMap
    const layerRef = React.useRef<VectorLayer<VectorSource> | null>(null)

    // 统一计算图层是否应该显示
    const shouldShow = React.useMemo(() => {
      return display == null || display
    }, [display])

    // 坐标转换函数
    const transformTo3857 = React.useCallback((coord: number[]) => {
      return fromLonLat(coord)
    }, [])

    // 创建序号标签样式
    const createNumberLabelStyles = React.useCallback((
      geometry: geom.Geometry,
      baseStyle: style.Style
    ): style.Style[] => {
      const geoType = geometry.getType()
      let coordinates: number[][] = []

      if (geoType === 'LineString') {
        coordinates = (geometry as geom.LineString).getCoordinates() || []
      } else if (geoType === 'Polygon') {
        const rings = (geometry as geom.Polygon).getCoordinates() || []
        if (rings.length > 0) {
          coordinates = rings[0] || []
        }
      }

      if (!coordinates || coordinates.length === 0) {
        return [baseStyle]
      }

      // 如果是闭合多边形，去掉最后一个重复的点
      if (coordinates.length > 1) {
        const first = coordinates[0]
        const last = coordinates[coordinates.length - 1]
        if (first && last && first[0] === last[0] && first[1] === last[1]) {
          coordinates = coordinates.slice(0, coordinates.length - 1)
        }
      }

      // 创建序号标签样式
      const labelStyles = coordinates.map((coord, index) => new style.Style({
        geometry: new geom.Point(coord),
        text: new style.Text({
          text: String(index + 1),
          font: '12px Calibri,sans-serif',
          fill: new style.Fill({ color: '#000000' }),
          stroke: new style.Stroke({ color: '#ffffff', width: 2 }),
          offsetY: -12,
        })
      }))

      return [baseStyle, ...labelStyles]
    }, [])

    // 根据 data 绘制图层
    React.useEffect(() => {
      if (!map) return

      // 先移除旧图层
      if (layerRef.current) {
        map.removeLayer(layerRef.current)
        layerRef.current = null
      }

      if (!data || !Array.isArray(data) || !data.length) return

      const features: Feature[] = []

      data.forEach((item) => {
        if (!item.type || !item.coordinates) return

        let featureGeom: geom.Geometry | null = null

        if (item.type === 'Point') {
          const coord = item.coordinates as number[]
          if (!coord || coord.length < 2) return
          featureGeom = new geom.Point(transformTo3857(coord))
        } else if (item.type === 'LineString') {
          const coords = (item.coordinates || []) as number[][]
          if (!coords.length) return
          featureGeom = new geom.LineString(coords.map(c => transformTo3857(c)))
        } else if (item.type === 'Polygon') {
          const rings = (item.coordinates || []) as number[][][]
          if (!rings.length) return
          const transformed = rings.map(r => r.map(c => transformTo3857(c)))
          featureGeom = new geom.Polygon(transformed)
        } else if (item.type === 'Circle') {
          const circleCoords = item.coordinates as { center: number[]; radius: number }
          const center = circleCoords?.center
          const radius = circleCoords?.radius
          if (!center || !radius) return
          featureGeom = new geom.Circle(transformTo3857(center), radius)
        }

        if (!featureGeom) return

        const f = new Feature({
          geometry: featureGeom,
          polygonId: item.id,
          polygonType: item.type,
          polygonStyle: item.style,
          cellKey,
        })
        features.push(f)
      })

      if (!features.length) return

      const source = new VectorSource({ features })
      const layer = new VectorLayer({
        source,
        properties: { layerType: 'polygon', cellKey },
        zIndex: 50,
      })

      // 样式函数
      layer.setStyle((feature) => {
        const geometry = feature.getGeometry()
        if (!geometry) return undefined

        const geomType = geometry.getType()
        const featureStyle = feature.get('polygonStyle') || {}

        // 根据几何类型获取样式
        const styleKey = geomType === 'Point' ? 'icon' 
          : geomType === 'LineString' ? 'line'
          : geomType === 'Polygon' ? 'polygon'
          : geomType === 'Circle' ? 'circle'
          : 'polygon'

        const mergedStyle = { ...defaultStyle[styleKey as keyof PolygonStyle], ...featureStyle[styleKey] }

        if (geomType === 'Point') {
          const iconStyle = mergedStyle as PolygonStyle['icon']
          return new style.Style({
            image: new style.Icon({
              src: iconStyle?.src || DEFAULT_POINT_ICON,
              scale: iconStyle?.scale || 1,
              anchor: [0.5, 1],
              displacement: [iconStyle?.displacementX || 0, iconStyle?.displacementY || 0],
            }),
          })
        }

        // 线、面、圆
        const lineStyle = mergedStyle as { color?: string; width?: number; fillColor?: string; snumber?: boolean }
        const strokeColor = lineStyle?.color || 'rgba(255, 0, 0, 0.8)'
        const strokeWidth = lineStyle?.width || 2
        const fillColor = lineStyle?.fillColor || 'rgba(255, 0, 0, 0.2)'

        const baseStyle = new style.Style({
          stroke: new style.Stroke({
            color: strokeColor,
            width: strokeWidth,
          }),
          fill: new style.Fill({
            color: fillColor,
          }),
        })

        // 检查是否需要绘制序号
        if (lineStyle?.snumber && (geomType === 'LineString' || geomType === 'Polygon')) {
          return createNumberLabelStyles(geometry as geom.Geometry, baseStyle)
        }

        return baseStyle
      })

      layer.setVisible(shouldShow)
      map.addLayer(layer)
      layerRef.current = layer

      return () => {
        if (layerRef.current && map) {
          map.removeLayer(layerRef.current)
          layerRef.current = null
        }
      }
    }, [map, JSON.stringify(data), JSON.stringify(defaultStyle), cellKey, transformTo3857, createNumberLabelStyles])

    // display 变化时，仅更新图层可见性
    React.useEffect(() => {
      if (!map || !layerRef.current) return
      layerRef.current.setVisible(shouldShow)
    }, [map, shouldShow])

    // 绘制工具栏
    const renderToolbar = () => {
      if (!showToolbar || readonly) return null

      const tools: { type: DrawType; label: string; icon: string }[] = [
        { type: 'Point', label: '点', icon: '📍' },
        { type: 'LineString', label: '线段', icon: '📏' },
        { type: 'Polygon', label: '多边形', icon: '⬡' },
        { type: 'Circle', label: '圆', icon: '⭕' },
      ]

      return (
        <div className="absolute top-2 left-2 z-20 flex gap-1 bg-white rounded-lg shadow-md p-1">
          {tools.map((tool) => (
            <button
              key={tool.type}
              className={cn(
                "w-8 h-8 flex items-center justify-center rounded transition-colors",
                drawType === tool.type 
                  ? "bg-blue-500 text-white" 
                  : "hover:bg-gray-100"
              )}
              title={tool.label}
              onClick={() => onDrawTypeChange?.(drawType === tool.type ? null : tool.type)}
            >
              {tool.icon}
            </button>
          ))}
        </div>
      )
    }

    return (
      <div
        ref={ref}
        className={cn("polygon-views relative", className)}
        data-cell-key={cellKey}
        {...props}
      >
        {renderToolbar()}
      </div>
    )
  }
)

PolygonViews.displayName = "PolygonViews"

export { PolygonViews }

import * as React from "react"
import { cn } from "@/lib/utils"
import Map from 'ol/Map'
import View from 'ol/View'
import TileLayer from 'ol/layer/Tile'
import XYZ from 'ol/source/XYZ'
import { fromLonLat, transformExtent } from 'ol/proj'
import { Zoom, ScaleLine, defaults as defaultControls } from 'ol/control'
import 'ol/ol.css'

// Map Context 用于向子组件传递 map 实例
export interface MapContextValue {
  map: Map | null
}

export const MapContext = React.createContext<MapContextValue>({ map: null })

// Hook 用于获取 map 实例
export const useMap = () => {
  const context = React.useContext(MapContext)
  return context.map
}

export interface ViewOptions {
  position?: {
    center?: [number, number]
    pick?: boolean
  }
  resetCenter?: {
    tableData?: Array<{ id: string; _table: string }>
  }
  zoom?: number
  maxZoom?: number
  minZoom?: number
  rotation?: number
  recordRotationActive?: boolean
  resolution?: number
  animation?: boolean
  duration?: number
}

export interface ZoomOption {
  show?: boolean
  zoomInTipLabel?: string
  zoomOutTipLabel?: string
  minZoom?: number
  maxZoom?: number
}

export interface ScaleLineOption {
  show?: boolean
  minWidth?: number
  units?: 'metric' | 'us' | 'nautical' | 'imperial' | 'degrees'
  steps?: number
  bar?: boolean
  text?: boolean
}

export interface ExtentOption {
  westLon?: number
  southLat?: number
  eastLon?: number
  northLat?: number
}

export interface MapContainerProps {
  /**
   * 视图配置
   */
  viewOptions?: ViewOptions
  /**
   * 缩放控件配置
   */
  zoomOption?: ZoomOption
  /**
   * 比例尺配置
   */
  scaleLine?: ScaleLineOption
  /**
   * 拖拽边界范围
   */
  extentOption?: ExtentOption
  /**
   * 宽度
   */
  width?: number | string
  /**
   * 高度
   */
  height?: number | string
  /**
   * CSS 类名
   */
  className?: string
  /**
   * 单元格唯一标识
   */
  cellKey?: string
  /**
   * 子元素
   */
  children?: React.ReactNode
}

// 默认中心点坐标 (北京)
const DEFAULT_CENTER: [number, number] = [116.391, 39.9042]

// 高德地图瓦片图层
const createTileLayer = () => {
  return new TileLayer({
    source: new XYZ({
      url: 'http://wprd0{1-4}.is.autonavi.com/appmaptile?lang=zh_cn&size=1&style=7&x={x}&y={y}&z={z}',
      crossOrigin: 'anonymous',
    }),
  })
}

const MapContainer = React.forwardRef<HTMLDivElement, MapContainerProps>(
  (
    {
      className,
      viewOptions = {
        position: {
          center: DEFAULT_CENTER,
          pick: false
        },
        zoom: 10,
        maxZoom: 18,
        minZoom: 3,
        rotation: 0,
        recordRotationActive: false,
        animation: true,
        duration: 1000
      },
      zoomOption = {
        show: true,
        zoomInTipLabel: '放大',
        zoomOutTipLabel: '缩小',
        minZoom: 3,
        maxZoom: 18
      },
      scaleLine = {
        show: true,
        bar: false,
        text: false
      },
      extentOption,
      width = '100%',
      height = '100%',
      cellKey,
      children,
      ...props
    },
    ref
  ) => {
    const containerRef = React.useRef<HTMLDivElement>(null)
    const mapRef = React.useRef<HTMLDivElement>(null)
    const [mapInstance, setMapInstance] = React.useState<Map | null>(null)
    const [mapReady, setMapReady] = React.useState(false)

    // 合并 ref
    React.useImperativeHandle(ref, () => containerRef.current as HTMLDivElement)

    // 获取配置值
    const center = viewOptions?.position?.center || DEFAULT_CENTER
    const zoom = viewOptions?.zoom ?? 10
    const maxZoom = viewOptions?.maxZoom ?? 18
    const minZoom = viewOptions?.minZoom ?? 3
    const rotation = viewOptions?.rotation ?? 0
    const animation = viewOptions?.animation ?? true
    const duration = viewOptions?.duration ?? 1000

    // 初始化地图
    React.useEffect(() => {
      if (!mapRef.current || mapInstance) return

      // 构建视图配置
      const viewConfig: Record<string, unknown> = {
        center: fromLonLat(center),
        zoom,
        maxZoom,
        minZoom,
        rotation: (rotation * Math.PI) / 180, // 角度转弧度
      }

      // 处理边界范围
      if (extentOption) {
        const { northLat, eastLon, southLat, westLon } = extentOption
        if (northLat && eastLon && southLat && westLon) {
          const fixedExtent = [
            Math.min(westLon, eastLon),
            southLat,
            Math.max(westLon, eastLon),
            northLat
          ]
          viewConfig.extent = transformExtent(fixedExtent, 'EPSG:4326', 'EPSG:3857')
        }
      }

      // 创建地图实例
      const map = new Map({
        target: mapRef.current,
        layers: [createTileLayer()],
        view: new View(viewConfig),
        controls: defaultControls({
          zoom: false,
          attribution: false,
          rotate: false,
        }),
      })

      // 添加缩放控件
      if (zoomOption?.show) {
        map.addControl(new Zoom({
          zoomInTipLabel: zoomOption.zoomInTipLabel || '放大',
          zoomOutTipLabel: zoomOption.zoomOutTipLabel || '缩小',
        }))
      }

      // 添加比例尺
      if (scaleLine?.show) {
        map.addControl(new ScaleLine({
          units: scaleLine.units || 'metric',
          bar: scaleLine.bar || false,
          text: scaleLine.text || false,
          minWidth: scaleLine.minWidth,
          steps: scaleLine.steps,
        }))
      }

      setMapInstance(map)
      setMapReady(true)

      // 监听容器大小变化
      const resizeObserver = new ResizeObserver(() => {
        map.updateSize()
      })
      if (mapRef.current) {
        resizeObserver.observe(mapRef.current)
      }

      return () => {
        resizeObserver.disconnect()
        if (map) {
          map.setTarget(undefined)
          setMapInstance(null)
        }
      }
    }, [])

    // 更新中心位置
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()
      const newCenter = fromLonLat(center)

      if (animation) {
        view.animate({ center: newCenter, duration })
      } else {
        view.setCenter(newCenter)
      }
    }, [center[0], center[1], mapReady])

    // 更新缩放级别
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()

      if (animation) {
        view.animate({ zoom, duration })
      } else {
        view.setZoom(zoom)
      }
    }, [zoom, mapReady])

    // 更新最大/最小缩放
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()
      view.setMaxZoom(maxZoom)
      view.setMinZoom(minZoom)
    }, [maxZoom, minZoom, mapReady])

    // 更新旋转角度
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()
      const radians = (rotation * Math.PI) / 180

      if (animation) {
        view.animate({ rotation: radians, duration })
      } else {
        view.setRotation(radians)
      }
    }, [rotation, mapReady])

    // 更新缩放控件
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const controls = mapInstance.getControls().getArray()
      const zoomControl = controls.find((c: unknown) => c instanceof Zoom)

      if (!zoomOption?.show && zoomControl) {
        mapInstance.removeControl(zoomControl)
      } else if (zoomOption?.show && !zoomControl) {
        mapInstance.addControl(new Zoom({
          zoomInTipLabel: zoomOption.zoomInTipLabel || '放大',
          zoomOutTipLabel: zoomOption.zoomOutTipLabel || '缩小',
        }))
      }
    }, [zoomOption?.show, mapReady, mapInstance])

    // 更新比例尺
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const controls = mapInstance.getControls().getArray()
      const scaleLineControl = controls.find((c: unknown) => c instanceof ScaleLine)

      if (scaleLineControl) {
        mapInstance.removeControl(scaleLineControl)
      }

      if (scaleLine?.show) {
        mapInstance.addControl(new ScaleLine({
          units: scaleLine.units || 'metric',
          bar: scaleLine.bar || false,
          text: scaleLine.text || false,
          minWidth: scaleLine.minWidth,
          steps: scaleLine.steps,
        }))
      }
    }, [scaleLine?.show, scaleLine?.units, scaleLine?.bar, scaleLine?.text, mapReady, mapInstance])

    return (
      <div
        ref={containerRef}
        className={cn(
          "relative overflow-hidden",
          className
        )}
        style={{
          width: typeof width === 'number' ? `${width}px` : width,
          height: typeof height === 'number' ? `${height}px` : height
        }}
        data-cell-key={cellKey}
        {...props}
      >
        {/* OpenLayers 地图容器 */}
        <div 
          ref={mapRef} 
          className="absolute inset-0"
          style={{ width: '100%', height: '100%' }}
        />

        {/* 子元素容器 - 通过 Context 传递 map 实例 */}
        {children && (
          <MapContext.Provider value={{ map: mapInstance }}>
            <div className="absolute inset-0 pointer-events-none z-10">
              <div className="pointer-events-auto">
                {mapReady ? children : null}
              </div>
            </div>
          </MapContext.Provider>
        )}
      </div>
    )
  }
)

MapContainer.displayName = "MapContainer"

export { MapContainer }
